			// Write to temp file for backward compatibility
			await writeFile(logFile, logLine, { flag: "a" });

			// Persist to state store
			const stateStore = executor.getStateStore();
			await stateStore.saveExecutionLog(planExecId, logContent);
		} catch {
			// Ignore write errors
		}
	};

